  class SecureSQLQueryExecutor(spark: SparkSession) {

    private val MAX_QUERY_LENGTH = 50000
    private val MAX_RESULT_ROWS = 100000
    private val QUERY_TIMEOUT_SECONDS = 300
    
    private val DANGEROUS_KEYWORDS = Set(
      "DROP", "DELETE", "TRUNCATE", "ALTER", "CREATE", "GRANT", "REVOKE",
      "INSERT", "UPDATE", "MERGE", "REPLACE", "LOAD", "EXPORT"
    )
    
