    def validateQuery(query: String): QueryValidationResult = {
      val errors = scala.collection.mutable.ListBuffer[String]()

      if (query == null || query.trim.isEmpty) {
        errors += "Query cannot be empty"
        return QueryValidationResult(false, None, errors.toList)
      }

      if (query.length > MAX_QUERY_LENGTH) {
        errors += s"Query exceeds maximum length of $MAX_QUERY_LENGTH characters"
      }

      val normalizedQuery = query.toUpperCase.replaceAll("\\s+", " ").trim
      
      val words = normalizedQuery.split("\\s+")
      val foundDangerousKeywords = DANGEROUS_KEYWORDS.filter(kw => words.contains(kw))
      if (foundDangerousKeywords.nonEmpty) {
        errors += s"Query contains forbidden keywords: ${foundDangerousKeywords.mkString(", ")}"
      }

      val foundForbiddenFunctions = FORBIDDEN_FUNCTIONS.filter(fn => 
        normalizedQuery.contains(fn.toUpperCase)
      )
      if (foundForbiddenFunctions.nonEmpty) {
        errors += s"Query contains forbidden functions: ${foundForbiddenFunctions.mkString(", ")}"
      }

      if (normalizedQuery.contains("--;") || 
          normalizedQuery.contains("/*") || 
          normalizedQuery.contains("*/") ||
          normalizedQuery.contains("UNION") && normalizedQuery.contains("SELECT")) {
        errors += "Query contains potential SQL injection patterns"
      }

      if (errors.nonEmpty) {
        QueryValidationResult(false, None, errors.toList)
      } else {
        QueryValidationResult(true, Some(query.trim), List.empty)
      }
    }

    def executeQuery(query: String, maxRows: Int = MAX_RESULT_ROWS): QueryResult = {
