      Try {
        spark.sparkContext.setJobDescription(s"User Query: ${sanitizedQuery.take(100)}")
        spark.sparkContext.setLocalProperty("spark.scheduler.pool", "user_queries")
        
        val df = spark.sql(sanitizedQuery)
        
        val limitedDf = df.limit(maxRows)
        
        val resultData = limitedDf.collect().map { row =>
          row.schema.fields.map { field =>
            field.name -> (if (row.isNullAt(row.fieldIndex(field.name))) null else row.get(row.fieldIndex(field.name)))
          }.toMap
        }

        val executionTime = System.currentTimeMillis() - startTime

        QueryResult(
          success = true,
          data = Some(resultData),
          schema = Some(df.schema),
          rowCount = Some(resultData.length.toLong),
          executionTimeMs = Some(executionTime)
        )
      } match {
        case Success(result) => result
        case Failure(exception) =>
          val executionTime = System.currentTimeMillis() - startTime
          val errorMessage = exception match {
            case pe: ParseException => s"SQL syntax error: ${pe.getMessage}"
            case ae: org.apache.spark.sql.AnalysisException => s"Query analysis error: ${ae.getMessage}"
            case _ => s"Query execution error: ${exception.getMessage}"
          }
          
          QueryResult(
            success = false,
            executionTimeMs = Some(executionTime),
            error = Some(errorMessage)
          )
      } finally {
        spark.sparkContext.clearJobGroup()
        spark.sparkContext.setLocalProperty("spark.scheduler.pool", null)
      }
    }

    def executeQueryWithTimeout(query: String, timeoutSeconds: Int = QUERY_TIMEOUT_SECONDS): QueryResult = {
      import scala.concurrent._
      import scala.concurrent.duration._
      import ExecutionContext.Implicits.global

      val futureResult = Future {
        executeQuery(query)
      }

      Try {
        Await.result(futureResult, timeoutSeconds.seconds)
      } match {
        case Success(result) => result
        case Failure(_: TimeoutException) =>
          QueryResult(
            success = false,
            error = Some(s"Query execution timeout after $timeoutSeconds seconds")
          )
        case Failure(exception) =>
          QueryResult(
            success = false,
            error = Some(s"Query execution failed: ${exception.getMessage}")
          )
      }
    }

    def explainQuery(query: String): QueryResult = {
      val validation = validateQuery(query)
      if (!validation.isValid) {
        return QueryResult(
          success = false,
          error = Some(s"Query validation failed: ${validation.errors.mkString("; ")}")
        )
