      Try {
        val df = spark.sql(validation.sanitizedQuery.get)
        val explainString = df.queryExecution.toString()
        
        val resultMap = Map("explanation" -> explainString)
        
        QueryResult(
          success = true,
          data = Some(Array(resultMap)),
          rowCount = Some(1)
        )
      } match {
        case Success(result) => result
        case Failure(exception) =>
          QueryResult(
            success = false,
            error = Some(s"Explain query failed: ${exception.getMessage}")
          )
      }
    }
  }

